def canMakeSubsequence(str1: str, str2: str) -> bool:
    j = 0
    m, n = len(str1), len(str2)

    for i in range(m):
        if j < n and (str1[i] == str2[j] or chr((ord(str1[i]) - ord('a') + 1) % 26 + ord('a')) == str2[j]):
            j += 1

    return j == n
